<template>
  <v-row justify="center">
    <v-dialog
      :model-value="dialog"
      transition="dialog-bottom-transition"
      fullscreen
    >
      <!-- <v-col col="12" sm="12" md="12" lg="12"> -->
      <v-card class="mx-auto card" width="100%">
        <div ref="scrollContainer" class="scroll-container">
          <v-card-title class="d-flex justify-end mx-12">
            <v-btn variant="text" class="vbtn-base" @click="$emit('popClose')">
              <Icon
                icon="mingcute:arrow-right-line"
                color="#000000"
                width="24"
                class="ml-2"
              />
              <h4 style="color: #000000">العودة للقائمة الرئيسية</h4></v-btn
            ></v-card-title
          >

          <v-card class="mx-auto card-payments pb-3 pt-2" width="92%">
            <v-card-title>
              <span
                style="display: flex; align-items: center; gap: 8px"
                class="mb-2"
              >
                <h5 style="font-weight: 400">فواتير ومدفوعات الزبون</h5>
                <v-spacer></v-spacer>
                <h5 style="font-weight: 400">إجمالي المستحق</h5>
              </span>

              <span style="display: flex; align-items: center; gap: 8px">
                <span style="display: flex; align-items: center; gap: 8px">
                  <Icon icon="solar:user-linear" color="#ffffff" width="25" />
                  <h5 style="font-weight: 400">
                    {{ debtor_user.debtorUser?.name }}
                  </h5>
                </span>
                <span style="display: flex; align-items: center; gap: 8px">
                  <Icon icon="uil:phone" color="#ffffff" width="25" />
                  <h5 style="font-weight: 400">
                    {{ debtor_user.debtorUser?.phone }}
                  </h5>
                </span>

                <v-spacer></v-spacer>
                <h4 style="font-weight: 400">
                  {{
                    $filters.formatNumber(
                      debtor_user.debtorUser?.remaining_amount
                    )
                  }}
                  د.ع
                </h4>
              </span>
              <span
                style="display: flex; align-items: center; gap: 8px"
                class="mt-2"
              >
                <v-spacer></v-spacer>
                <v-btn
                  variant="text"
                  density="comfortable"
                  class="btn-Comprehensive-invoice"
                  size="large"
                  @click="get_invoice(debtor_user.debtorUser?.id)"
                  :loading="loading_data_invoice"
                >
                  <Icon
                    icon="stash:invoice"
                    class="ml-1"
                    color="#ffffff"
                    width="25"
                  />
                  <h4 style="font-weight: 400">فاتورة شاملة</h4>
                </v-btn>

                <v-btn
                  variant="text"
                  density="comfortable"
                  class="btn-add-payment"
                  size="large"
                  @click="
                    pop_add_new_payment(
                      debtor_user.debtorUser?.remaining_amount
                    )
                  "
                  :loading="loading_add_payment"
                >
                  <Icon
                    icon="fluent:payment-48-regular"
                    class="ml-2"
                    color="#ffffff"
                    width="25"
                  />
                  <h4 style="font-weight: 400">تسجيل دفعة نقدية</h4>
                </v-btn>
              </span>
            </v-card-title>
          </v-card>

          <v-row class="py-2 mt-2 mx-15" style="flex: none !important">
            <v-col col="12" sm="6" md="3" lg="3">
              <v-card class="card-statistics py-2">
                <v-card-title>
                  <h4 style="color: #624fc6">{{ debtor_user.total_sales }}</h4>
                  <h5 style="font-weight: 400">عدد الفواتير</h5>
                </v-card-title>
              </v-card>
            </v-col>
            <v-col col="12" sm="6" md="3" lg="3">
              <v-card class="card-statistics py-2">
                <v-card-title>
                  <h4 style="color: green">{{ debtor_user.paid }}</h4>
                  <h5 style="font-weight: 400">الفواتير المدفوعة</h5>
                </v-card-title>
              </v-card>
            </v-col>
            <v-col col="12" sm="6" md="3" lg="3">
              <v-card class="card-statistics py-2">
                <v-card-title>
                  <h4 style="color: red">{{ debtor_user.unpaid }}</h4>
                  <h5 style="font-weight: 400">الفواتير الغير مدفوعة</h5>
                </v-card-title>
              </v-card>
            </v-col>
            <v-col col="12" sm="6" md="3" lg="3">
              <v-card class="card-statistics py-2">
                <v-card-title>
                  <h4 style="color: #f57c00">
                    {{ debtor_user.partially_paid }}
                  </h4>
                  <h5 style="font-weight: 400">الفواتير المدفوعة جزئيا</h5>
                </v-card-title>
              </v-card>
            </v-col>
          </v-row>
          <v-row class="mx-15" style="flex: none !important">
            <v-col col="12" sm="12" md="6" lg="6" class="">
              <v-card
                style="
                  box-shadow: 0px 0px 0px 0px !important;
                  padding-bottom: 6px;
                  border-radius: 8px;
                "
                class="mx-auto"
                width="100%"
              >
                <v-card-title class="mx-auto">
                  <v-text-field
                    v-model="debtor_query"
                    @input="query_change"
                    density="compact"
                    class="font-weight-black custom-input"
                    type="text"
                    color="#624fc6"
                    label="بحث"
                    variant="outlined"
                    clearable
                    lazy-rules
                    persistent-hint
                    hide-details="auto"
                  />
                </v-card-title>
              </v-card>
            </v-col>
            <v-col col="12" sm="12" md="6" lg="6" class="">
              <v-card
                style="
                  box-shadow: 0px 0px 0px 0px !important;
                  border-radius: 8px;
                "
                class="mx-auto"
                width="100%"
              >
                <v-card-title class="mx-auto">
                  <span
                    class="border-filter py-1"
                    style="display: flex; align-items: center; gap: 10px"
                  >
                    <v-btn
                      variant="text"
                      density="comfortable"
                      class="btn-filter"
                      :class="payment_status == null ? 'all' : ''"
                      @click="filterStatus('All')"
                    >
                      <h4 class="h5-text">الجميع</h4>
                    </v-btn>

                    <v-btn
                      variant="text"
                      density="comfortable"
                      class="btn-filter"
                      :class="payment_status == 'paid' ? 'paid' : ''"
                      @click="filterStatus('paid')"
                    >
                      <Icon
                        icon="prime:check-circle"
                        class="ml-1"
                        :color="
                          payment_status == 'paid' ? '#ffffff' : '#2e5c8a'
                        "
                        width="20"
                        height="20"
                      />
                      <h4 class="h5-text">مدفوعة</h4>
                    </v-btn>
                    <v-btn
                      variant="text"
                      density="comfortable"
                      class="btn-filter"
                      :class="
                        payment_status == 'partially_paid'
                          ? 'partially_paid'
                          : ''
                      "
                      @click="filterStatus('partially_paid')"
                    >
                      <Icon
                        icon="prime:times-circle"
                        class="ml-1"
                        :color="
                          payment_status == 'partially_paid'
                            ? '#ffffff'
                            : '#2e5c8a'
                        "
                        width="20"
                        height="20"
                      />
                      <h4 class="h5-text">مدفوعة جزئيا</h4>
                    </v-btn>
                    <v-btn
                      variant="text"
                      density="comfortable"
                      class="btn-filter"
                      :class="payment_status == 'unpaid' ? 'unpaid' : ''"
                      @click="filterStatus('unpaid')"
                    >
                      <Icon
                        icon="weui:time-outlined"
                        class="ml-1"
                        :color="
                          payment_status == 'unpaid' ? '#ffffff' : '#2e5c8a'
                        "
                        width="19"
                        height="19"
                      />
                      <h4 class="h5-text">غير مدفوعة</h4>
                    </v-btn>
                  </span>
                </v-card-title>
              </v-card>
            </v-col>
          </v-row>

          <v-row
            class="py-2 mr-15 ml-13 row-wrapper"
            style="flex: none !important"
          >
            <v-col
              col="12"
              sm="12"
              md="12"
              lg="12"
              v-for="(debtor, index) in sales_debtor"
              :key="index"
              @click="get_all_info_sale(debtor.id, index)"
            >
              <v-card class="card-items-sales py-2">
                <v-card-title>
                  <span style="display: flex; align-items: center; gap: 8px">
                    <h5 style="color: #624fc6">
                      # {{ debtor.invoice_number }}
                    </h5>
                    <h5
                      class="payment-status paid"
                      v-if="debtor.payment_status == 'paid'"
                    >
                      مدفوعة
                    </h5>
                    <h5
                      class="payment-status partially-paid"
                      v-else-if="debtor.payment_status == 'partially_paid'"
                    >
                      مدفوعة جزئيا
                    </h5>
                    <h5 class="payment-status unpaid" v-else>غير مدفوعة</h5>

                    <span
                      class="items-retrieve totally-back"
                      style="display: flex; align-items: center; gap: 8px"
                      v-if="debtor.retrieve == 1"
                    >
                      <Icon icon="lucide:rotate-ccw" width="20" />
                      <h5 style="font-weight: 400">راجعة كليًا</h5>
                    </span>

                    <span
                      class="items-retrieve partially-reviewed"
                      style="display: flex; align-items: center; gap: 8px"
                      v-else-if="debtor.partial_return"
                    >
                      <Icon icon="lucide:rotate-ccw" width="20" />
                      <h5 style="font-weight: 400">راجعة جزئيًا</h5>
                    </span>
                  </span>
                </v-card-title>
                <v-card-title>
                  <span style="display: flex; align-items: center; gap: 100px">
                    <span style="display: flex; align-items: center; gap: 8px">
                      <Icon
                        icon="uil:calendar"
                        color="#6c757d"
                        width="24"
                        class="ml-2"
                      />
                      <span
                        style="
                          display: flex;
                          flex-direction: column;
                          line-height: 1.5;
                        "
                      >
                        <h5 style="font-weight: 401; color: #6c757d">
                          التاريخ
                        </h5>
                        <h5 style="font-weight: 400" dir="ltr">
                          {{
                            $moment(debtor.created_at)
                              .tz("Asia/Baghdad")
                              .format("YYYY-MM-DD hh:mm A")
                          }}
                        </h5>
                      </span>
                    </span>
                    <!-- 
                  <span style="display: flex; align-items: center; gap: 8px">
                    <Icon
                      icon="fluent:payment-32-regular"
                      color="#6c757d"
                      width="24"
                      class="ml-2"
                    />
                    <span
                      style="
                        display: flex;
                        flex-direction: column;
                        line-height: 1.5;
                      "
                    >
                      <h5 style="font-weight: 401; color: #6c757d">
                        عدد الدفعات
                      </h5>
                      <h5 style="font-weight: 400">
                        {{ debtor.payment_dates.length }} دفعة
                      </h5>
                    </span>
                  </span> -->

                    <span style="display: flex; align-items: center; gap: 8px">
                      <Icon
                        icon="solar:box-linear"
                        color="#6c757d"
                        width="24"
                        class="ml-2"
                      />
                      <span
                        style="
                          display: flex;
                          flex-direction: column;
                          line-height: 1.5;
                        "
                      >
                        <h5 style="font-weight: 401; color: #6c757d">
                          عدد الاصناف
                        </h5>
                        <h5 style="font-weight: 400">
                          {{ debtor.items_count }}
                        </h5>
                      </span>
                    </span>

                    <span style="display: flex; align-items: center; gap: 8px">
                      <span
                        style="
                          display: flex;
                          flex-direction: column;
                          line-height: 1.5;
                        "
                      >
                        <h5 style="font-weight: 401; color: #6c757d">
                          الاجمالي
                        </h5>
                        <h5 style="font-weight: 400; color: #624fc6">
                          {{ $filters.formatNumber(debtor.total) }} د.ع
                        </h5>
                      </span>
                    </span>

                    <span style="display: flex; align-items: center; gap: 8px">
                      <span
                        style="
                          display: flex;
                          flex-direction: column;
                          line-height: 1.5;
                        "
                      >
                        <h5 style="font-weight: 500; color: #6c757d">
                          المدفوع
                        </h5>
                        <h5 style="font-weight: 400; color: green">
                          {{
                            $filters.formatNumber(
                              debtor.payment_dates.amount_paid
                            )
                          }}
                          د.ع
                        </h5>
                      </span>
                    </span>

                    <span style="display: flex; align-items: center; gap: 8px">
                      <span
                        style="
                          display: flex;
                          flex-direction: column;
                          line-height: 1.5;
                        "
                      >
                        <h5 style="font-weight: 401; color: #6b7280">
                          المتبقي
                        </h5>
                        <h5 style="font-weight: 400; color: #f57c00">
                          {{
                            $filters.formatNumber(
                              debtor.payment_dates.remaining_amount
                            )
                          }}
                          د.ع
                        </h5>
                      </span>
                    </span>
                    <v-spacer></v-spacer>
                    <span
                      v-if="
                        !debitsStore.loading_sales_debtor_with_payment_items ||
                        index !== index_load
                      "
                      style="display: flex; align-items: center; gap: 8px"
                      class="mt-n10"
                    >
                      <h5 style="font-weight: 401; color: #6b7280">
                        المبالغ المالية
                      </h5>
                      <Icon
                        icon="ep:arrow-left-bold"
                        width="24"
                        height="24"
                        color="#6b7280"
                      />
                    </span>

                    <span
                      v-else-if="
                        debitsStore.loading_sales_debtor_with_payment_items &&
                        index === index_load
                      "
                      style="display: flex; align-items: center; gap: 8px"
                      class="mt-n10"
                    >
                      <v-progress-circular
                        indeterminate
                        color="#624fc6"
                        size="24"
                        width="3"
                      />
                    </span>
                  </span>
                </v-card-title>
              </v-card>
            </v-col>

            <!-- sentinel في الأسفل للمراقبة -->
            <div ref="sentinel"></div>

            <!-- حالة التحميل / لا مزيد -->
            <v-col
              col="12"
              sm="12"
              md="12"
              lg="12"
              v-if="loading"
              style="text-align: center; padding: 12px"
            >
              <h4 class="text-center py-4">
                <img src="./Loading.gif" alt="" />
              </h4>
            </v-col>
            <v-col
              col="12"
              sm="12"
              md="12"
              lg="12"
              v-if="
                loading == false &&
                sales_debtor.length == 0 &&
                debtor_query != null
              "
              style="text-align: center; padding: 12px"
            >
              <h4 class="text-center mt-16">
                <img
                  src="./empty-box.png"
                  alt=""
                  width="200px"
                  height="200px"
                />
              </h4>
              <h4>لايوجد نتائج</h4>
            </v-col>
          </v-row>
        </div>
      </v-card>
    </v-dialog>
    <PopItems :dialog="dialog_items" @popClose="dialog_items = false" />
    <PopAddNewPayment
      :amount="amount"
      :dialog="dialog_payemnt"
      @popClose="dialog_payemnt = false"
      @addPayment="addPayment"
    />
  </v-row>
</template>
<script setup>
import { ref, watch, onBeforeUnmount, computed } from "vue";
import { useDebitsStore } from "@/stores/debits";
import { h, render, nextTick } from "vue";
import PopItems from "@/components/debtor/PopItems.vue";
import ComprehensiveInvoice from "@/components/layout/ComprehensiveInvoice.vue";
import PopAddNewPayment from "@/components/debtor/PopAddNewPayment.vue";
import { useSnackbarStore } from "@/stores/snackbar";

const dialog_items = ref(false);
const dialog_payemnt = ref(false);
const amount = ref(null);

const props = defineProps({
  dialog: { type: Boolean, default: false },
});

const debitsStore = useDebitsStore();
const index_load = ref(null);
const sales_debtor = computed(() => debitsStore.sales_debtor);
const loading = computed(() => debitsStore.loading_debtor);

const loading_data_invoice = computed(() => debitsStore.loading_data_invoice);

const debtor_user = computed(() => debitsStore.statistics_debtor_user);
const payment_status = computed(() => debitsStore.payment_status);
const loading_add_payment = computed(() => debitsStore.loading_add_payment2);

const debtor_query = computed({
  get: () => debitsStore.debtor_query,
  set: (val) => (debitsStore.debtor_query = val),
});

const scrollContainer = ref(null);
const sentinel = ref(null);
let observer = null;

let timerId = null;
function query_change() {
  clearTimeout(timerId);
  timerId = setTimeout(() => {
    debitsStore.sales_debtor = [];
    debitsStore.params_debtor.page = 1;
    debitsStore.debtor_state = "done";
    debitsStore.loading_debtor = false;

    debitsStore.get_sales_to_debtor();
  }, 1000);
}

function filterStatus(item) {
  if (item === "All") {
    debitsStore.payment_status = null;
  } else {
    debitsStore.payment_status = item;
  }
  debitsStore.sales_debtor = [];
  debitsStore.params_debtor.page = 1;
  debitsStore.debtor_state = "done";
  debitsStore.loading_debtor = false;
  debitsStore.get_sales_to_debtor();
}

// استدعاء لجلب البيانات (يبقى في Pinia)
function get_sales_to_debtor() {
  debitsStore.get_sales_to_debtor();
}

function pop_add_new_payment(newAmount) {
  dialog_payemnt.value = true;
  amount.value = newAmount;
}

async function addPayment(newAmount) {
  let data = {};
  data["id"] = debtor_user.value.debtorUser?.id;
  data["amount_paid"] = newAmount;

  dialog_payemnt.value = false;
  // استدعاء الدالة وانتظارها
  await debitsStore.add_payment(data);
  await debitsStore.get_statistics_debtor_user();

  debitsStore.sales_debtor = [];
  debitsStore.params_debtor.page = 1;
  debitsStore.debtor_state = "done";
  await debitsStore.get_sales_to_debtor();

  const snackbar = useSnackbarStore();
  snackbar.showMessage({
    color: "deep-purple-accent-4",
    icon: "clarity:success-standard-solid",
    text: "تم احضار اضافة دفعة بنجاح",
  });
  debitsStore.loading_add_payment2 = false;
}

async function get_all_info_sale(id, index) {
  debitsStore.loading_sales_debtor_with_payment_items = true;
  index_load.value = index;
  debitsStore.sale_id = id;

  // استدعاء الدالة وانتظارها
  await debitsStore.get_sales_to_debtor_with_payments_items();

  // بعد انتهاء التحميل
  debitsStore.loading_sales_debtor_with_payment_items = false;
  dialog_items.value = true;
}

// إنشاء الـ IntersectionObserver
function createObserver() {
  if (!sentinel.value) return;
  // root هو عنصر التمرير نفسه حتى نراقب التداخل داخل الحاوية
  const rootEl = scrollContainer.value || null;

  observer = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          // فقط اجلب إذا الحوار مفتوح، وليس في حالة تحميل، ولم تنتهي البيانات
          if (
            props.dialog &&
            !loading.value &&
            debitsStore.debtor_state !== "finished"
          ) {
            get_sales_to_debtor();
          }
        }
      });
    },
    {
      root: rootEl,
      rootMargin: "0px",
      threshold: 0.1,
    }
  );

  observer.observe(sentinel.value);
}

function destroyObserver() {
  if (observer) {
    if (sentinel.value) observer.unobserve(sentinel.value);
    observer.disconnect();
    observer = null;
  }
}

async function get_invoice(id) {
  let data = {};
  data["id"] = id;
  await debitsStore.get_invoice_to_print(data);
  printInvoice(debitsStore.data_invoice);
}
// طباعة فاتورة
const paperSize = ref("size-80");
const nameStore = ref("علاء حداد فرع الديوانية");

let isPrinting = false;

function printInvoice(items) {
  if (isPrinting) return;
  isPrinting = true;

  // حاوية الطباعة المباشرة تحت body
  const container = document.createElement("div");
  container.id = "print-root"; // مهم جداً للـ CSS أدناه
  container.style.position = "fixed";
  container.style.left = "0";
  container.style.top = "0";
  container.style.zIndex = "2147483647";
  document.body.appendChild(container);

  const cleanup = () => {
    render(null, container);
    container.remove();
    window.removeEventListener("afterprint", cleanup);
    isPrinting = false;
  };

  const vnode = h(ComprehensiveInvoice, {
    purchasedItems: items.sales,
    nameStore: nameStore.value,
    paperSize: paperSize.value,
    name: items.name,
    phone: items.phone,
    city: items.city,
    remaining_amount_all: items.remaining_amount,
    onReady: async () => {
      await nextTick();
      requestAnimationFrame(() => {
        window.addEventListener("afterprint", cleanup, { once: true });
        window.print(); // نسخة واحدة فقط
      });
    },
  });

  render(vnode, container);
}

// عندما يفتح الحوار
watch(
  () => props.dialog,
  (open) => {
    if (open) {
      // أنشئ المراقب (انتبه أنّ sentinel قد لا يوجد فورا — لذا نستخدم nextTick إن لزم)
      // ننتظر وجود العناصر ثم ننشئ المراقب
      setTimeout(() => {
        destroyObserver();
        createObserver();
      }, 50);
    } else {
      destroyObserver();
    }
  },
  { immediate: false }
);

watch(debtor_query, (newVal) => {
  if (newVal === null || newVal === "") {
    debitsStore.params_debtor.page = 1;
    get_sales_to_debtor();
  }
});
onBeforeUnmount(() => {
  destroyObserver();
});
</script>
<style scoped>
.card {
  box-shadow: 0px 0px 0px 0px;
  background: #f4f2fb;
}
.card-payments {
  box-shadow: 0px 0px 0px 0px;
  color: #ffffff;
  border-radius: 8px;
  background: linear-gradient(to right bottom, #090040, #624fc6);
}

.vbtn-base:hover {
  background-color: #e5e7eb !important;
  border-radius: 0.375rem;
}
.card-statistics {
  border-radius: 8px;
  background-color: #ffffff !important;

  cursor: pointer;
  box-shadow: 0 5px 15px rgb(0 0 0 / 7%) !important;
  transition: all ease 0.2s;
}

.card-statistics:hover {
  transition: all ease 0.2s;
  transform: scale(0.9);
  box-shadow: 0 5px 15px rgb(0 0 0 / 20%) !important;
}

.card-items-sales {
  border-radius: 8px;
