import { defineStore } from "pinia";
import axios from "axios";
import { useSnackbarStore } from "@/stores/snackbar";
import { server } from "@/config";

export const useStatisticsStore = defineStore("statistics", {
  state: () => ({
    statistics: [],
    loading: false,
    year_sales_sum_statistics: {},
    range_sales_statistics: null,
    range_loading: false,
  }),
  actions: {
    async get_statistics() {
      this.loading = true;
      try {
        const response = await axios.get(`${server}/api/get_statistics`);
        const statistics = response.data.result;

        let data = [
          {
            title: "دخل اليوم",
            statistics: statistics.dailyIncome,
            color: "#624fc6",
            icon: "solar:chat-round-money-bold-duotone",
          },

          {
            title: "دخل الاسبوع",
            statistics: statistics.weeklyIncome,
            color: "#1F8A70",
            icon: "solar:money-bag-bold-duotone",
          },
          {
            title: "كمية المبيعات اليوم",
            statistics: statistics.todaySoldItems,
            color: "#D2649A",
            icon: "ic:outline-today",
          },
          {
            title: "كمية المبيعات الاسبوع",
            statistics: statistics.weeklySoldItems,
            color: "#405D72",
            icon: "tabler:calendar-week",
          },

          {
            title: "رواجع اليوم",
            statistics: statistics.dailyRetrieval,
            color: "#1976D2",
            icon: "streamline:money-graph-arrow-decrease-down-stats-graph-descend-right-arrow",
          },

          {
            title: "رواجع الاسبوع",
            statistics: statistics.weeklyRetrieval,
            color: "#8E24AA",
            icon: "streamline-ultimate:performance-money-decrease-bold",
          },
          {
            title: "كمية رواجع اليوم",
            statistics: statistics.todayRetrievalItems,
            color: "#5D4037",
            icon: "ic:outline-today",
          },
          {
            title: "كمية رواجع الاسبوع",
            statistics: statistics.weeklyRetrievalItems,
            color: "#F57C00",
            icon: "tabler:calendar-week",
          },
          // debit
          {
            title: "دين اليوم",
            statistics: statistics.dailyIncomeDebt,
            color: "#FFA726",
            icon: "solar:chat-round-money-broken",
          },

          {
            title: "الدين الكلي",
            statistics: statistics.allIncomeDebt,
            color: "#E65100",
            icon: "solar:money-bag-broken",
          },
          {
            title: "كمية دين اليوم",
            statistics: statistics.todaySoldItemsDebt,
            color: "#BF360C",
            icon: "ic:outline-today",
          },
          {
            title: "كمية الدين الكلي",
            statistics: statistics.allSoldItemsDebt,
            color: "#FFAB00",
            icon: "tabler:calendar-week",
          },

          // delivery
          
          {
            title: "مجموع طلبات الاسبوع",
            statistics: statistics.weeklyIncomeDelivery,
            color: "#880E4F",
            icon: "iconamoon:delivery-duotone",
          },
          {
            title: "كمية طلبات الراجعة",
            statistics: statistics.deliveryWeeklyRetrievalItems,
            color: "#AD1457",
            icon: "lineicons:truck-delivery-1",
          },
          {
            title: "كمية طلبات اليوم",
            statistics: statistics.todaySoldItemsDelivery,
            color: "#FF80AB",
            icon: "hugeicons:delivery-delay-02",
          },
          {
            title: "كمية طلبات الاسبوع",
            statistics: statistics.weeklySoldItemsDelivery,
            color: "#F50057",
            icon: "hugeicons:delivery-delay-02",
          },
        ];

        // Bar
        let object = {};
        let datasets = [];
        let chartData = {};
        (object["label"] = "احصائات المبيعات"),
          (object["backgroundColor"] = "rgba(98,79,198, 0.5)"),
          (object["borderColor"] = "#624fc6"),
          (object["pointRadius"] = 7),
          (object["pointHoverRadius"] = 13),
          (object["pointStyle"] = "circle"),
          (object["data"] = statistics.yearSalesSumStatistics[0]),
          datasets.push(object);

        let object2 = {};
        (object2["label"] = "احصائيات رواجع المبيعات"),
          (object2["backgroundColor"] = "rgba(255,99,132, 0.5)"),
          (object2["borderColor"] = "#FF6384"),
          (object2["pointRadius"] = 7),
          (object2["pointHoverRadius"] = 13),
          (object2["pointStyle"] = "circle"),
          (object2["data"] = statistics.yearSalesRetrievalSumStatistics[0]),
          datasets.push(object2);

        chartData["datasets"] = datasets;
        chartData["labels"] = statistics.yearSalesSumStatistics[1];

        this.statistics = data;
        this.year_sales_sum_statistics = chartData;
        this.loading = false;

        return response;
      } catch (error) {
        this.loading = false;

        const snackbar = useSnackbarStore();

        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";

        snackbar.showMessage({
          color: "#B71C1C",
          icon: "ri:close-circle-fill",
          text: message,
        });

        throw error;
      }
    },
    async fetch_range_sales_statistics(dateFrom, dateTo) {
      this.range_loading = true;
      try {
        const response = await axios.get(
          `${server}/api/get_range_sales_statistics`,
          {
            params: {
              date_from: dateFrom,
              date_to: dateTo,
            },
          }
        );
        const r = response.data.result;

        const object = {
          label: "احصائات المبيعات",
          backgroundColor: "rgba(98,79,198, 0.5)",
          borderColor: "#624fc6",
          pointRadius: 4,
          pointHoverRadius: 8,
          pointStyle: "circle",
          data: r.rangeSalesSumStatistics[0],
        };
        const object2 = {
          label: "احصائيات رواجع المبيعات",
          backgroundColor: "rgba(255,99,132, 0.5)",
          borderColor: "#FF6384",
          pointRadius: 4,
          pointHoverRadius: 8,
          pointStyle: "circle",
          data: r.rangeSalesRetrievalSumStatistics[0],
        };

        this.range_sales_statistics = {
          datasets: [object, object2],
          labels: r.rangeSalesSumStatistics[1],
        };
        this.range_loading = false;
        return response;
      } catch (error) {
        this.range_loading = false;
        const snackbar = useSnackbarStore();
        const errorData = error.response?.data;
        const message =
          [errorData?.message, ...Object.values(errorData?.errors || {}).flat()]
            .filter(Boolean)
            .join("\n") || "حدث خطأ غير متوقع";
        snackbar.showMessage({
          color: "#B71C1C",
          icon: "ri:close-circle-fill",
          text: message,
        });
        throw error;
      }
    },
    hideMessage() {
      this.snackbar = false;
      this.snack_message = null;
    },
  },
  getters: {
    isSnackbarVisible: (state) => state.snackbar,
  },
});
