<template>
  <v-row justify="center">
    <v-dialog
      :model-value="dialog"
      transition="dialog-bottom-transition"
      max-width="600"
      width="600"
    >
      <v-card class="mx-auto card" width="100%">
        <v-toolbar dark color="#624fc6">
          <v-btn
            icon
            fab
            color="#ffffff"
            x-small
            @click="$emit('popClose')"
            class="mr-1"
          >
            <Icon
              class="icon_download"
              icon="ic:outline-close"
              color="#ffffff"
              width="25"
            />
          </v-btn>

          <v-toolbar-title class="mx-auto d-flex justify-center pl-14">
            <h4 style="font-family: 'Cairo', sans-serif">انشاء مستخدم</h4>
          </v-toolbar-title>
        </v-toolbar>
        <v-card-text class="mt-4 d-flex justify-stert">
          <v-row>
            <v-col cols="12" sm="12" md="12" lg="12">
              <Input
                v-model="name"
                @update-value="name = $event"
                autocomplete="name"
                type="text"
                label="اسم الزبون"
              />
            </v-col>

            <v-col cols="12" sm="12" md="12" lg="12">
              <Input
                v-model="city"
                @update-value="city = $event"
                autocomplete="city"
                type="text"
                label="المدينة"
              />
            </v-col>

            <v-col cols="12" sm="12" md="12" lg="12">
              <Input
                v-model="phone"
                @update-value="phone = $event"
                autocomplete="phone"
                type="number"
                label="رقم الهاتف"
              />
            </v-col>
          </v-row>
        </v-card-text>
        <v-card-actions class="mt-5 pb-5">
          <v-btn
            size="large"
            v-on:click="add_user"
            color="#624fc6"
            class="px-16 mx-auto border-btn"
            elevation="4"
            variant="flat"
            :loading="loading"
          >
            <h4 style="color: white; font-size: 17px">تاكيد</h4>
          </v-btn>
        </v-card-actions>
      </v-card>
    </v-dialog>
  </v-row>
</template>
<script setup>
import Input from "@/components/layout/Input.vue";
import { ref, defineEmits,computed } from "vue";
const emit = defineEmits(["popClose"]);
import { useDebitsStore } from "@/stores/debits";
const debitsStore = useDebitsStore();
const name = ref("");
const city = ref("");
const phone = ref("");

defineProps({
  dialog: {
    type: Boolean,
    default: false,
  },
  title: {
    type: [String],
    default: null,
  },
});

const loading = computed(() => debitsStore.loading_add_user);

async function add_user() {
  let data = {
    name: name.value,
    city: city.value,
    phone: phone.value,
  };
  try {
    await debitsStore.add_debtor_users(data);
  } catch (error) {
    console.error("حدث خطأ أثناء إضافة المستخدم:", error);
  }
  emit("popClose");
}
</script>
<style scoped>
.card {
  border-radius: 25px !important;
  box-shadow: 0px 0px 0px 0px !important;
}
</style>
